    (function(){
        const colors = ['#ffffff','#ffffff','#ffffff','#ffffff','#7dd3fc','#7dd3fc','#c4b5fd','#c4b5fd','#f9a8d4','#a5f3fc','#e9d5ff'];
        const rnd = (a,b) => a + Math.random()*(b-a);

        function makeSpark(size, color) {
            const h = size/2, q = size/4;
            const el = document.createElementNS('http://www.w3.org/2000/svg','svg');
            el.setAttribute('viewBox',`0 0 ${size} ${size}`);
            el.setAttribute('width', size); el.setAttribute('height', size);
            el.style.cssText = 'overflow:visible;display:block;flex-shrink:0;';
            const p = document.createElementNS('http://www.w3.org/2000/svg','path');
            p.setAttribute('d',`M${h},0 L${h+q*.3},${h-q*.3} L${size},${h} L${h+q*.3},${h+q*.3} L${h},${size} L${h-q*.3},${h+q*.3} L0,${h} L${h-q*.3},${h-q*.3} Z`);
            p.setAttribute('fill', color);
            el.appendChild(p);
            return el;
        }

        function spawnGlitter(container, count) {
            for (let i = 0; i < count; i++) {
                const isSpark = Math.random() < 0.5;
                const size    = isSpark ? rnd(3, 8) : rnd(1, 3);
                const color   = colors[Math.floor(Math.random()*colors.length)];
                const dur     = rnd(1.6, 5);
                const delay   = rnd(0, 5);
                const minOp   = rnd(0, 0.06);
                const maxOp   = rnd(0.55, 1);
                const pulse   = rnd(1.2, 2.2);
                const wrap    = document.createElement('div');
                wrap.style.cssText = `position:absolute;left:${rnd(0,100)}%;top:${rnd(0,100)}%;width:${size}px;height:${size}px;pointer-events:none;animation:starTwinkle ${dur}s ease-in-out ${delay}s infinite;--min-op:${minOp};--max-op:${maxOp};--pulse:${pulse};transform-origin:center;display:flex;align-items:center;justify-content:center;`;
                if (isSpark) { wrap.appendChild(makeSpark(size, color)); }
                else { wrap.style.borderRadius='50%'; wrap.style.background=color; wrap.style.boxShadow=`0 0 ${size*2.5}px ${color}`; }
                container.appendChild(wrap);
            }
        }

        /* Loader glitter removed — skeleton has no glitter */

        /* Top-up modal glitters */
        function initTuGlitters() {
            const tl = document.getElementById('tuGlitterLayer');
            if (tl && tl.childElementCount === 0) spawnGlitter(tl, 32);
        }
        const _origOpen = window.openTopUpModal;
        window.openTopUpModal = function() {
            if (_origOpen) _origOpen.apply(this, arguments);
            setTimeout(initTuGlitters, 60);
        };
    })();
    

    // Global balance formatter — strips .00 for whole numbers, keeps real cents
    window.fmtBal = function(n){ var v=parseFloat(n)||0; if(v===0) return '$0.00'; return '$'+String(Math.floor(v)).replace(/\B(?=(\d{3})+(?!\d))/g,','); };

    //  FEATURED LISTINGS — spotlight rotator (pre-rendered, clean transitions, 24h cache) 
    (function initFeaturedListings() {
        const CACHE_KEY = 'siterifty_featured_v1';
        const CACHE_TTL = 24 * 60 * 60 * 1000; // 24 hours

        function saveCache(entries) {
            try {
                localStorage.setItem(CACHE_KEY, JSON.stringify({ ts: Date.now(), data: entries }));
            } catch(e) {}
        }

        function loadCache() {
            try {
                const raw = localStorage.getItem(CACHE_KEY);
                if (!raw) return null;
                const parsed = JSON.parse(raw);
                if (!parsed || !parsed.ts || !parsed.data) return null;
                if (Date.now() - parsed.ts > CACHE_TTL) { localStorage.removeItem(CACHE_KEY); return null; }
                return parsed.data; // [[id, site], ...]
            } catch(e) { return null; }
        }
        const NICHE_SVG = {
            saas:       '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><rect x="2" y="4" width="14" height="10" rx="2" stroke="#a855f7" stroke-width="1.3"/><path d="M6 4V3a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v1" stroke="#a855f7" stroke-width="1.3"/><circle cx="9" cy="9" r="1.5" fill="#a855f7"/><path d="M9 10.5v2" stroke="#a855f7" stroke-width="1.2" stroke-linecap="round"/></svg>',
            content:    '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><rect x="3" y="2" width="12" height="14" rx="2" stroke="#818cf8" stroke-width="1.3"/><path d="M6 6h6M6 9h6M6 12h4" stroke="#818cf8" stroke-width="1.2" stroke-linecap="round"/></svg>',
            newsletter: '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><rect x="2" y="4" width="14" height="10" rx="2" stroke="#38bdf8" stroke-width="1.3"/><path d="M2 7l7 4 7-4" stroke="#38bdf8" stroke-width="1.2" stroke-linecap="round"/></svg>',
            ecommerce:  '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><path d="M3 3h2l1.5 7h7l1.5-5H6" stroke="#34d399" stroke-width="1.3" stroke-linecap="round" stroke-linejoin="round"/><circle cx="8" cy="14.5" r="1" fill="#34d399"/><circle cx="13" cy="14.5" r="1" fill="#34d399"/></svg>',
            directory:  '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><path d="M3 5a2 2 0 0 1 2-2h3l2 2h5a2 2 0 0 1 2 2v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5z" stroke="#fbbf24" stroke-width="1.3"/></svg>',
            tool:       '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><path d="M13 3a3 3 0 0 1 0 6l-7 7-3-3 7-7a3 3 0 0 1 3-3z" stroke="#a855f7" stroke-width="1.3" stroke-linejoin="round"/><circle cx="4.5" cy="13.5" r="1.5" stroke="#a855f7" stroke-width="1.2"/></svg>',
            extension:  '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><rect x="2" y="2" width="6" height="6" rx="1.5" stroke="#818cf8" stroke-width="1.3"/><rect x="10" y="2" width="6" height="6" rx="1.5" stroke="#818cf8" stroke-width="1.3"/><rect x="2" y="10" width="6" height="6" rx="1.5" stroke="#818cf8" stroke-width="1.3"/><rect x="10" y="10" width="6" height="6" rx="1.5" stroke="#38bdf8" stroke-width="1.3"/></svg>',
            app:        '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><rect x="5" y="1" width="8" height="16" rx="2" stroke="#38bdf8" stroke-width="1.3"/><circle cx="9" cy="14" r="1" fill="#38bdf8"/><path d="M7 4h4" stroke="#38bdf8" stroke-width="1.2" stroke-linecap="round"/></svg>',
            blog:       '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><path d="M3 4h12M3 8h8M3 12h6" stroke="#fbbf24" stroke-width="1.3" stroke-linecap="round"/><circle cx="14" cy="12" r="2.5" stroke="#fbbf24" stroke-width="1.2"/><path d="M15.8 14.8l2 2" stroke="#fbbf24" stroke-width="1.3" stroke-linecap="round"/></svg>',
            affiliate:  '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="6.5" stroke="#34d399" stroke-width="1.3"/><path d="M9 5.5v1M9 11.5v1M6.5 9h5" stroke="#34d399" stroke-width="1.3" stroke-linecap="round"/><path d="M7.5 7.5h3v3h-3z" stroke="#34d399" stroke-width="1.2"/></svg>',
            default:    '<svg width="32" height="32" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="6.5" stroke="#8b8aa8" stroke-width="1.3"/><path d="M2.5 9h13M9 2.5a10 6.5 0 0 0 0 13M9 2.5a10 6.5 0 0 1 0 13" stroke="#8b8aa8" stroke-width="1.2"/></svg>'
        };

        function nicheIcon(niche) {
            if (!niche) return NICHE_SVG.default;
            const k = niche.toLowerCase();
            for (const key of Object.keys(NICHE_SVG)) {
                if (k.includes(key)) return NICHE_SVG[key];
            }
            return NICHE_SVG.default;
        }

        function fmtPrice(v) {
            if (!v && v !== 0) return '—';
            const n = parseFloat(v);
            if (isNaN(n)) return v;
            if (n >= 1000) return '$' + (n / 1000).toFixed(n % 1000 === 0 ? 0 : 1) + 'k';
            return '$' + n.toLocaleString();
        }

        function fmtRevenue(v) {
            if (!v && v !== 0) return null;
            const n = parseFloat(String(v).replace(/[^0-9.]/g, ''));
            if (isNaN(n) || n === 0) return null;
            if (n >= 1000) return '$' + (n / 1000).toFixed(1) + 'k/mo';
            return '$' + Math.round(n) + '/mo';
        }

        function cardBadge(site) {
            if (site.featured) return '<span class="feat-card-badge featured">Featured</span>';
            const age = Date.now() - (site.createdAt || 0);
            if (age < 1000 * 60 * 60 * 48) return '<span class="feat-card-badge new">New</span>';
            if (site.views > 50) return '<span class="feat-card-badge hot">Hot</span>';
            return '';
        }

        function getThumbUrl(site) {
            const raw = site.images || site.image || site.thumbnail || site.screenshot;
            if (!raw) return null;
            if (typeof raw === 'string' && raw) return raw;
            if (Array.isArray(raw) && raw[0]) return raw[0];
            if (typeof raw === 'object') {
                const vals = Object.values(raw).filter(Boolean);
                if (vals[0]) return vals[0];
            }
            return null;
        }

        function renderCard(id, site) {
            const icon = nicheIcon(site.niche || site.category);
            const price = fmtPrice(site.price || site.askingPrice);
            const rev = fmtRevenue(site.monthlyRevenue || site.revenue);
            const expenses = site.expenses != null ? parseFloat(site.expenses) : null;
            const revRaw = site.monthlyRevenue || site.revenue;
            const revNum = revRaw ? parseFloat(String(revRaw).replace(/[^0-9.]/g,'')) : null;
            const profit = (revNum != null && expenses != null) ? revNum - expenses : null;
            const traffic = site.monthlyTraffic || site.traffic;
            const title = site.title || site.name || site.url || 'Untitled listing';
            const desc = site.description || site.shortDesc || '';
            const niche = site.niche || site.category || 'Website';
            const siteUrl = site.url ? site.url.replace(/^https?:\/\//,'').replace(/\/$/,'') : '';
            const age = site.age || '';
            const thumbUrl = getThumbUrl(site);

            const chips = [
                rev    ? `<div class="feat-stat-chip green">Rev <span>${rev}</span></div>` : '',
                profit != null ? `<div class="feat-stat-chip ${profit >= 0 ? 'green' : 'red'}">Profit <span>${profit >= 0 ? '+' : '-'}$${Math.abs(profit).toLocaleString()}</span></div>` : '',
                traffic ? `<div class="feat-stat-chip">Traffic <span>${Number(traffic) >= 1000 ? (Number(traffic)/1000).toFixed(1)+'k/mo' : traffic+'/mo'}</span></div>` : '',
                age    ? `<div class="feat-stat-chip">Age <span>${age}</span></div>` : '',
            ].filter(Boolean).join('');

            const thumbHtml = thumbUrl
                ? `<img src="${thumbUrl}" alt="${title}" loading="lazy" onerror="this.style.display='none';this.nextElementSibling.style.display='flex';">
                   <div class="feat-card-thumb-fallback" style="display:none;">${icon}</div>
                   <div class="feat-thumb-fade"></div>`
                : `<div class="feat-card-thumb-fallback">${icon}</div>
                   <div class="feat-thumb-fade"></div>`;

            return `
            <div class="feat-card" onclick="handleFeaturedClick('${id}')">
                <div class="feat-card-thumb">${thumbHtml}</div>
                <div class="feat-card-body">
                    <div class="feat-card-top">
                        <div class="feat-card-title">${title}</div>
                        ${cardBadge(site)}
                    </div>
                    ${siteUrl ? `<div class="feat-card-url">${siteUrl}</div>` : ''}
                    ${desc     ? `<div class="feat-card-desc">${desc}</div>`  : ''}
                    ${chips    ? `<div class="feat-card-chips">${chips}</div>` : ''}
                    <div class="feat-card-footer">
                        <div class="feat-card-price">${price}</div>
                        <div style="display:flex;align-items:center;gap:5px;">
                            <div class="feat-card-type">${niche}</div>
                            <button class="feat-offer-btn" onclick="(function(e){e.stopPropagation();if(!window._fbAuth||!window._fbAuth.currentUser){if(typeof openAuthModal==='function')openAuthModal();return;}if(typeof openSettingsPanel==='function'){openSettingsPanel('offers');}else{window.location.href='/listing?id=${id}';}})(event)">
                                <svg width="8" height="8" viewBox="0 0 9 9" fill="none"><path d="M1 4.5h7M5 1.5l3 3-3 3" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"/></svg>
                                View
                            </button>
                        </div>
                    </div>
                </div>
            </div>`;
        }

        //  Rotator state 
        let _entries = [];
        let _current = 0;
        let _timer   = null;
        let _progTimer = null;
        const INTERVAL = 3000; // 3 s per card

        function buildSlides(entries) {
            const spotlight = document.getElementById('featSpotlight');
            const dotsEl    = document.getElementById('featDots');
            const navEl     = document.getElementById('featNav');
            if (!spotlight) return;

            spotlight.innerHTML = '';
            spotlight.style.transform = 'translateX(0)';

            entries.forEach(([id, site], i) => {
                const slide = document.createElement('div');
                slide.className = 'feat-slide' + (i === 0 ? ' active' : '');
                slide.innerHTML = renderCard(id, site);
                spotlight.appendChild(slide);
            });

            // Build dots
            if (dotsEl) {
                dotsEl.innerHTML = '';
                entries.forEach((_, i) => {
                    const dot = document.createElement('button');
                    dot.className = 'feat-dot' + (i === 0 ? ' active' : '');
                    dot.setAttribute('aria-label', 'Go to listing ' + (i + 1));
                    dot.onclick = () => goTo(i, true);
                    dotsEl.appendChild(dot);
                });
            }

            // Show controls if >1 slide
            if (navEl) navEl.style.display = entries.length > 1 ? 'flex' : 'none';

            _current = 0;
            // Start auto-rotate
            clearInterval(_timer);
            if (entries.length > 1) {
                _timer = setInterval(advance, INTERVAL);
            }
        }

        function goTo(idx, manual) {
            const spotlight = document.getElementById('featSpotlight');
            const dotsEl    = document.getElementById('featDots');
            if (!spotlight) return;

            const slides = spotlight.querySelectorAll('.feat-slide');
            const dots   = dotsEl ? dotsEl.querySelectorAll('.feat-dot') : [];
            const total  = slides.length;
            const next   = ((idx % total) + total) % total;

            if (next === _current) return;

            slides[_current].classList.remove('active');
            dots[_current] && dots[_current].classList.remove('active');

            _current = next;

            slides[_current].classList.add('active');
            dots[_current] && dots[_current].classList.add('active');

            // Slide the strip to show current card
            spotlight.style.transform = 'translateX(-' + (_current * 100) + '%)';

            if (manual) {
                clearInterval(_timer);
                _timer = setInterval(advance, INTERVAL);
            }
        }

        function advance() {
            const next = (_current + 1) % _entries.length;
            goTo(next, false);
        }

        window._featPrev = function() {
            const total = _entries.length;
            goTo(((_current - 1) + total) % total, true);
        };

        window._featNext = function() {
            goTo((_current + 1) % _entries.length, true);
        };

        function startProgress() { /* no-op — using dots instead */ }

        function renderFromEntries(entries) {
            const skeleton = document.getElementById('featSkeleton');
            const empty    = document.getElementById('featuredEmpty');
            if (skeleton) skeleton.style.display = 'none';

            if (!entries || entries.length === 0) {
                if (empty) empty.style.display = 'block';
                return;
            }

            _entries = entries;
            buildSlides(_entries);
        }

        function fetchFromFirebase() {
            const interval = setInterval(() => {
                if (!window._fbDb || !window._fbDbFns) return;
                clearInterval(interval);

                const { ref, get } = window._fbDbFns;
                get(ref(window._fbDb, 'websites'))
                    .then(snap => {
                        if (!snap || !snap.val()) {
                            // only show empty state if cache also had nothing
                            if (_entries.length === 0) {
                                const empty = document.getElementById('featuredEmpty');
                                if (empty) empty.style.display = 'block';
                            }
                            return;
                        }

                        const data = snap.val();
                        const fresh = Object.entries(data)
                            .filter(([, v]) => v && (v.title || v.name || v.url))
                            .sort(([, a], [, b]) => {
                                if (a.featured && !b.featured) return -1;
                                if (!a.featured && b.featured) return 1;
                                return (b.createdAt || 0) - (a.createdAt || 0);
                            })
                            .slice(0, 3);

                        if (fresh.length === 0) return;

                        // Save to cache for next 24h
                        saveCache(fresh);

                        // Only rebuild slides if data actually changed
                        const oldIds = _entries.map(([id]) => id).join(',');
                        const newIds = fresh.map(([id]) => id).join(',');
                        if (oldIds !== newIds) {
                            clearInterval(_timer);
                            _current = 0;
                            renderFromEntries(fresh);
                        }
                    })
                    .catch(() => {
                        if (_entries.length === 0) {
                            const section = document.getElementById('featuredSection');
                            if (section) section.style.display = 'none';
                        }
                    });
            }, 300);
            setTimeout(() => clearInterval(interval), 8000);
        }

        function loadListings() {
            //  Cache-first: serve instantly from localStorage, fetch in background if stale 
            const cached = loadCache();
            if (cached && cached.length > 0) {
                renderFromEntries(cached);
                // Still fetch in background to keep data fresh — but only updates DOM if IDs changed
                fetchFromFirebase();
            } else {
                // No cache — fetch from Firebase and show skeleton in the meantime
                fetchFromFirebase();
            }
        }

        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', loadListings);
        } else {
            loadListings();
        }
    })();

