//  Hero stats slot-machine animation — values persist across page loads (daily cache)
(function() {
    // Persistence key: resets at UTC midnight each day (matches /api/stats cadence)
    var _slotKey = 'sr_hero_slots_' + new Date().toISOString().slice(0, 10);

    // Fallback sequences used on very first visit (before /api/stats resolves)
    var defaultBuyers = [
        '1,000', '1,500', '2,000', '2,800', '3,500',
        '4,200', '5,100', '6,000', '7,200', '8,500', '10,000+'
    ];
    var defaultTransacted = [
        '$10K', '$15K', '$22K', '$31K', '$40K',
        '$52K', '$63K', '$74K', '$85K', '$95K', '$100K+'
    ];
    var fees = ['30%', '15%', '10%', '5%'];

    // Live sequences — overwritten once /api/stats resolves (see window._onHeroStats below)
    var buyers     = defaultBuyers.slice();
    var transacted = defaultTransacted.slice();

    // ── persistence helpers ──────────────────────────────────────────────────
    function _saveSlots(bVal, tVal, fVal) {
        try { localStorage.setItem(_slotKey, JSON.stringify({ b: bVal, t: tVal, f: fVal })); } catch(_) {}
    }
    function _loadSlots() {
        try {
            var raw = localStorage.getItem(_slotKey);
            if (raw) return JSON.parse(raw);
        } catch(_) {}
        return null;
    }

    // ── reel helpers ─────────────────────────────────────────────────────────
    function buildReel(el, items) {
        var reel = el.querySelector('.hero-slot-reel');
        reel.innerHTML = '';
        items.forEach(function(val) {
            var span = document.createElement('span');
            span.className = 'hero-slot-item';
            span.textContent = val;
            reel.appendChild(span);
        });
        var itemH = 20;
        el.style.height = itemH + 'px';
        reel.style.transform = 'translateY(0)';
        return { reel: reel, index: 0, total: items.length, itemH: itemH };
    }

    // Jump instantly to a specific value (no animation) — used when loading persisted data
    function jumpReel(el, items, value) {
        var idx = items.indexOf(value);
        if (idx < 0) idx = items.length - 1; // fallback to last
        var state = buildReel(el, items);
        state.index = idx;
        state.reel.style.transition = 'none';
        state.reel.style.transform = 'translateY(-' + (idx * state.itemH) + 'px)';
        return state;
    }

    function animateSlot(state, intervalMs, staggerMs, onDone) {
        var step = 0;
        function tick() {
            if (step >= state.total - 1) { if (onDone) onDone(); return; }
            step++;
            state.index = step;
            state.reel.style.transition = 'transform 0.18s cubic-bezier(0.22,1,0.36,1)';
            state.reel.style.transform = 'translateY(-' + (step * state.itemH) + 'px)';
            var delay = step >= state.total - 2 ? intervalMs * 1.8 : intervalMs;
            setTimeout(tick, delay);
        }
        setTimeout(tick, staggerMs);
    }

    // ── unpause hero CSS animations ──────────────────────────────────────────
    function _unpauseHero() {
        var statsEl = document.querySelector('.hero-stats');
        if (statsEl) statsEl.style.animationPlayState = 'running';

    }

    // ── main: show persisted values instantly OR animate + persist ────────────
    function startSlots() {
        var bEl = document.getElementById('slotBuyers');
        var tEl = document.getElementById('slotTransacted');
        var fEl = document.getElementById('slotFee');
        if (!bEl || !tEl || !fEl) return;

        _unpauseHero();

        var saved = _loadSlots();
        if (saved && saved.b && saved.t && saved.f) {
            // Already animated today — jump straight to the saved final values
            jumpReel(bEl, buyers,     saved.b);
            jumpReel(tEl, transacted, saved.t);
            jumpReel(fEl, fees,       saved.f);
            return;
        }

        // First visit today — run the animation then persist the final values
        var bFinal = buyers[buyers.length - 1];
        var tFinal = transacted[transacted.length - 1];
        var fFinal = fees[fees.length - 1];

        var bState = buildReel(bEl, buyers);
        var tState = buildReel(tEl, transacted);
        var fState = buildReel(fEl, fees);

        var startDelay = 400;
        var saved_ = false;
        function maybeSave() {
            if (saved_) return;
            saved_ = true;
            _saveSlots(bFinal, tFinal, fFinal);
        }

        animateSlot(bState, 700, startDelay, maybeSave);
        animateSlot(tState, 700, startDelay + 180);
        animateSlot(fState, 900, startDelay + 360);
    }

    // ── expose hook so /api/stats can update the sequences before animation ──
    // Called by the LIVE STATS script below when real data arrives
    window._onHeroStats = function(s) {
        // Build sequences that end on the real live value from the API
        // s.a = sellers/buyers (e.g. "12"), s.b = sites listed, fee is always 5%
        var liveB = s.a + 'k+';
        var liveT = s.b + 'k+'; // use listed count as proxy for transacted if no dedicated field

        // Only update if the live value isn't already the last item
        if (buyers[buyers.length - 1] !== liveB) {
            // Rebuild sequence ending at live value
            buyers = defaultBuyers.slice();
            if (buyers.indexOf(liveB) < 0) { buyers[buyers.length - 1] = liveB; }
        }
        if (transacted[transacted.length - 1] !== liveT) {
            transacted = defaultTransacted.slice();
            if (transacted.indexOf(liveT) < 0) { transacted[transacted.length - 1] = liveT; }
        }
    };

    document.addEventListener('DOMContentLoaded', function() {
        var bEl = document.getElementById('slotBuyers');
        var tEl = document.getElementById('slotTransacted');
        var fEl = document.getElementById('slotFee');
        if (!bEl || !tEl || !fEl) return;

        // Pre-build reels so the first item is visible during the loader
        buildReel(bEl, buyers);
        buildReel(tEl, transacted);
        buildReel(fEl, fees);

        // Hook into loader dismissal signal
        var prev = window._signalLoaderReady;
        window._signalLoaderReady = function() {
            if (prev) prev();
            startSlots();
        };

        // Safety fallback
        setTimeout(function() {
            var statsEl = document.querySelector('.hero-stats');
            if (statsEl && statsEl.style.animationPlayState !== 'running') {
                startSlots();
            }
        }, 3000);
    });
})();


//  Hero ticker — rotates phrases every 2s, text slides up from bottom 
(function() {
    var phrases = [
        'Buy &amp; sell sites',
        'Lowest fees',
        'Vetted listings',
        'Secure escrow',
        'For indie hackers',
        '10K+ buyers',
        'Close deals fast'
    ];
    var idx = 0;

    function nextPhrase() {
        var slot = document.getElementById('tickerWord');
        if (!slot) return;
        slot.classList.remove('entering');
        slot.classList.add('leaving');
        setTimeout(function() {
            idx = (idx + 1) % phrases.length;
            slot.innerHTML = phrases[idx];
            slot.classList.remove('leaving');
            slot.classList.add('entering');
        }, 290);
    }

    document.addEventListener('DOMContentLoaded', function() {
        setInterval(nextPhrase, 2000);
    });
})();


//  Seller Reputation Search 
// Debounced: waits 400ms after typing stops before hitting Firebase.
// On explicit button click (force=true) runs immediately.
(function() {
    var _srTimer = null;
    var _srLast  = '';

    window.sellerRepSearch = function(raw, force) {
        var q = (raw || '').trim().toLowerCase().replace(/^@/, '');
        if (!q) {
            _showRepPlaceholder();
            _srLast = '';
            clearTimeout(_srTimer);
            return;
        }
        if (q === _srLast && !force) return; // same query, no change

        clearTimeout(_srTimer);
        var delay = force ? 0 : 400;
        _srTimer = setTimeout(function() { _doSearch(q); }, delay);
    };

    function _showRepPlaceholder() {
        var el = document.getElementById('sellerRepResults');
        if (!el) return;
        el.innerHTML = '<svg width="36" height="36" viewBox="0 0 36 36" fill="none" style="display:block;margin:0 auto 10px;opacity:0.25;"><circle cx="18" cy="12" r="7" stroke="currentColor" stroke-width="1.8"/><path d="M5 32c0-7 5.8-12 13-12s13 5 13 12" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/></svg><div style="font-size:12px;color:rgba(139,138,168,0.4);">Enter a username to look up their reputation score</div>';
        el.style.cssText = 'background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.13);border-radius:13px;padding:20px;text-align:center;';
    }

    function _showRepLoading() {
        var el = document.getElementById('sellerRepResults');
        if (!el) return;
        el.style.cssText = 'background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.13);border-radius:13px;padding:20px;text-align:center;';
        el.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;gap:8px;font-size:12px;color:var(--muted);"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" style="animation:spin 1s linear infinite;flex-shrink:0;"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="2" stroke-dasharray="40" stroke-dashoffset="10" stroke-linecap="round"/></svg>Searching…</div>';
    }

    function _doSearch(username) {
        _srLast = username;
        _showRepLoading();

        var fns = window._fbDbFns;
        var db  = window._fbDb || window._db;
        if (!fns || !db) {
            _showRepError('Firebase not ready. Please try again.');
            return;
        }
        var ref = fns.ref, get = fns.get;

        // Step 1: look up uid from usernames index (one cheap read)
        get(ref(db, 'usernames/' + username)).then(function(snap) {
            if (!snap || !snap.exists()) {
                _showRepNotFound(username);
                return;
            }
            var uid = snap.val();
            // Step 2: fetch user profile (one read)
            return get(ref(db, 'users/' + uid)).then(function(uSnap) {
                if (!uSnap || !uSnap.exists()) { _showRepNotFound(username); return; }
                _showRepProfile(uSnap.val(), uid);
            });
        }).catch(function(err) {
            console.warn('[sellerRepSearch]', err);
            _showRepError('Could not load profile. Check your connection.');
        });
    }

    function _showRepNotFound(username) {
        var el = document.getElementById('sellerRepResults');
        if (!el) return;
        el.style.cssText = 'background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.13);border-radius:13px;padding:20px;text-align:center;';
        el.innerHTML = '<div style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:4px;">@' + _esc(username) + ' not found</div>'
            + '<div style="font-size:11px;color:var(--muted);">No Siterifty account with that username.</div>';
    }

    function _showRepError(msg) {
        var el = document.getElementById('sellerRepResults');
        if (!el) return;
        el.style.cssText = 'background:rgba(248,113,113,0.06);border:1px solid rgba(248,113,113,0.2);border-radius:13px;padding:20px;text-align:center;';
        el.innerHTML = '<div style="font-size:12px;color:var(--red);">' + _esc(msg) + '</div>';
    }

    function _showRepProfile(data, uid) {
        var el = document.getElementById('sellerRepResults');
        if (!el) return;

        var username   = data.username || 'Unknown';
        var plan       = (data.plan || 'Free');
        var planLow    = plan.toLowerCase();
        var deals      = parseInt(data.transactions || data.deals || 0);
        var rating     = parseFloat(data.rating || 0);
        var joinedTs   = data.createdAt || null;
        var lastSeenTs = data.lastSeen  || null;
        var listings   = parseInt(data.listingCount || 0);
        var bio        = data.bio || '';

        // Avatar
        var GRADS = [['#9b5de5','#e879a0'],['#38bdf8','#818cf8'],['#2dd4a0','#38bdf8'],['#f5c842','#f97316'],['#e879a0','#fb7185'],['#818cf8','#9b5de5']];
        var h = 0; for (var i = 0; i < uid.length; i++) h = (h * 31 + uid.charCodeAt(i)) >>> 0;
        var gc = GRADS[h % GRADS.length];
        var avStyle = 'background:linear-gradient(135deg,' + gc[0] + ',' + gc[1] + ');';
        var avHtml = data.photoURL
            ? '<img src="' + _esc(data.photoURL) + '" style="width:100%;height:100%;object-fit:cover;border-radius:999px;" onerror="this.style.display=\'none\'">'
            : username.charAt(0).toUpperCase();

        // Plan badge colour
        var planColor = planLow === 'pro' ? '#a855f7' : planLow === 'growth' ? '#38bdf8' : planLow === 'starter' ? '#34d399' : 'var(--muted)';

        // Stars
        var starsHtml = '';
        for (var s = 1; s <= 5; s++) {
            starsHtml += '<svg width="10" height="10" viewBox="0 0 10 10" fill="none"><path d="M5 1l1.18 2.39L9 3.82 7 5.76l.47 2.74L5 7.23 2.53 8.5 3 5.76 1 3.82l2.82-.43Z" fill="' + (s <= Math.round(rating) ? '#f5c842' : 'rgba(255,255,255,0.12)') + '"/></svg>';
        }

        // Joined / last seen
        var joinedStr  = joinedTs  ? 'Joined ' + _relDate(joinedTs)  : '';
        var lastStr    = lastSeenTs ? 'Active ' + _relDate(lastSeenTs) : '';

        el.style.cssText = 'border:1px solid rgba(255,255,255,0.1);border-radius:13px;overflow:hidden;';
        el.innerHTML = '<div style="padding:16px;display:flex;align-items:center;gap:12px;background:rgba(255,255,255,0.03);">'
            + '<div style="width:44px;height:44px;border-radius:999px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-family:\'Syne\',sans-serif;font-size:18px;font-weight:800;color:#fff;overflow:hidden;' + avStyle + '">' + avHtml + '</div>'
            + '<div style="flex:1;min-width:0;">'
            +   '<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;">'
            +     '<span style="font-family:\'Syne\',sans-serif;font-size:14px;font-weight:800;color:var(--text);">@' + _esc(username) + '</span>'
            +     '<span style="font-size:9px;font-weight:700;letter-spacing:.05em;padding:2px 7px;border-radius:4px;background:rgba(168,85,247,0.1);border:1px solid rgba(168,85,247,0.2);color:' + planColor + ';">' + _esc(plan).toUpperCase() + '</span>'
            +   '</div>'
            +   (bio ? '<div style="font-size:11px;color:var(--muted);margin-top:3px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + _esc(bio) + '</div>' : '')
            +   '<div style="font-size:10px;color:var(--muted);margin-top:2px;">' + (joinedStr ? joinedStr : '') + (lastStr && joinedStr ? ' · ' : '') + (lastStr || '') + '</div>'
            + '</div>'
            + '</div>'
            + '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:1px;background:rgba(255,255,255,0.07);">'
            +   _statCell(deals, 'Deals')
            +   _statCell(listings, 'Listings')
            +   _statCell(rating > 0 ? rating.toFixed(1) : '—', 'Rating', rating > 0 ? starsHtml : '')
            + '</div>';
    }

    function _statCell(val, label, extra) {
        return '<div style="background:var(--surface);padding:12px 8px;text-align:center;">'
            + '<div style="font-family:\'Syne\',sans-serif;font-size:16px;font-weight:800;color:var(--text);">' + val + '</div>'
            + '<div style="font-size:9.5px;color:var(--muted);margin-top:2px;">' + label + '</div>'
            + (extra ? '<div style="display:flex;gap:1px;justify-content:center;margin-top:4px;">' + extra + '</div>' : '')
            + '</div>';
    }

    function _relDate(ts) {
        var sec = Math.floor((Date.now() - ts) / 1000);
        if (sec < 86400)     return 'today';
        if (sec < 86400*7)   return Math.floor(sec/86400) + 'd ago';
        if (sec < 86400*30)  return Math.floor(sec/86400/7) + 'w ago';
        if (sec < 86400*365) return Math.floor(sec/86400/30) + 'mo ago';
        return Math.floor(sec/86400/365) + 'y ago';
    }

    function _esc(s) {
        return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }
})();


(function() {
'use strict';

// Admin email is read from Firebase at /adminEmail — never hardcoded.
// Loaded once when the admin panel auth fires via _loadAdminEmail().
let _adminEmailSys = null;

async function _loadAdminEmail() {
    try {
        const fns = window._fbDbFns;
        const database = window._fbDb || window._db;
        if (!fns || !database) return;
        const snap = await fns.get(fns.ref(database, 'adminEmail'));
        _adminEmailSys = snap.exists() ? snap.val().trim().toLowerCase() : null;
    } catch(e) {
        _adminEmailSys = null;
    }
}

function _isAdmin(user) {
    if (!user || !user.email || !_adminEmailSys) return false;
    return user.email.trim().toLowerCase() === _adminEmailSys;
}
function _auth(){ return window._fbAuth || window._auth; }
function _fns() { return window._fbDbFns; }
function _db()  { return window._fbDb  || window._db; }
function _ref(path)       { const f=_fns(); return f && f.ref(_db(), path); }
function _onVal(path, cb) { const f=_fns(); if(f && f.onValue) f.onValue(_ref(path), cb); }

// All admin actions go through the server API — bypasses Firebase DB security rules
async function adminAPI(method, route, body) {
    const user = _auth() && _auth().currentUser;
    if (!user) throw new Error('Not signed in');
    const token = await user.getIdToken();
    const opts = { method, headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' } };
    if (body) opts.body = JSON.stringify(body);
    const resp = await fetch('/api/' + route, opts);
    const data = await resp.json();
    if (!resp.ok) throw new Error(data.error || 'HTTP ' + resp.status);
    return data;
}

let _maintenanceActive = false;
let _currentUserBanned = false;
let _panelOpen = false;

// 
// MAINTENANCE
// 
function showMaintenance(msg, eta) {
    const user = _auth() && _auth().currentUser;
    if (_isAdmin(user)) return;
    document.getElementById('sysMaintenanceMsg').textContent = msg || "We're making some improvements. We'll be back shortly.";
    document.getElementById('sysMaintenanceEta').textContent = eta ? 'Estimated time: ' + eta : 'Estimated time: check back soon';
    document.getElementById('sysMaintenanceOverlay').style.display = 'flex';
}
function hideMaintenance() {
    document.getElementById('sysMaintenanceOverlay').style.display = 'none';
}
window.closeMaintenance = function() { hideMaintenance(); };

function syncMaintenanceUi(data) {
    const toggleEl = document.getElementById('adminToggleMaintenance');
    const trackEl  = document.getElementById('adminMaintenanceTrack');
    const thumbEl  = document.getElementById('adminMaintenanceThumb');
    const msgEl    = document.getElementById('adminMaintenanceMsg');
    const etaEl    = document.getElementById('adminMaintenanceEta');
    if (!data) data = {};
    const on = !!data.active;
    if (toggleEl) toggleEl.checked = on;
    if (trackEl)  trackEl.style.background = on ? '#a855f7' : 'rgba(255,255,255,0.1)';
    if (thumbEl)  thumbEl.style.transform  = on ? 'translateX(16px)' : 'translateX(0)';
    if (msgEl && data.message) msgEl.value = data.message;
    if (etaEl && data.eta)     etaEl.value = data.eta;
}

// Toggle via API — server writes to Firebase with service account (no rules block)
window.adminToggleMaintenance = async function(on) {
    const trackEl = document.getElementById('adminMaintenanceTrack');
    const thumbEl = document.getElementById('adminMaintenanceThumb');
    if (trackEl) trackEl.style.background = on ? '#a855f7' : 'rgba(255,255,255,0.1)';
    if (thumbEl) thumbEl.style.transform  = on ? 'translateX(16px)' : 'translateX(0)';
    const msg = (document.getElementById('adminMaintenanceMsg') || {}).value || '';
    const eta = (document.getElementById('adminMaintenanceEta') || {}).value || '';
    try {
        await adminAPI('POST', 'admin/maintenance', { active: on, message: msg, eta: eta });
    } catch(e) {
        console.warn('[maintenance toggle]', e);
        // Revert toggle on failure
        if (trackEl) trackEl.style.background = !on ? '#a855f7' : 'rgba(255,255,255,0.1)';
        if (thumbEl) thumbEl.style.transform  = !on ? 'translateX(16px)' : 'translateX(0)';
        const toggleEl = document.getElementById('adminToggleMaintenance');
        if (toggleEl) toggleEl.checked = !on;
    }
};
window.syncMaintenanceMsg = async function(v) {
    const on = (document.getElementById('adminToggleMaintenance') || {}).checked || false;
    const eta = (document.getElementById('adminMaintenanceEta') || {}).value || '';
    try { await adminAPI('POST', 'admin/maintenance', { active: on, message: v, eta: eta }); } catch(e) {}
};
window.syncMaintenanceEta = async function(v) {
    const on = (document.getElementById('adminToggleMaintenance') || {}).checked || false;
    const msg = (document.getElementById('adminMaintenanceMsg') || {}).value || '';
    try { await adminAPI('POST', 'admin/maintenance', { active: on, message: msg, eta: v }); } catch(e) {}
};

// 
// BAN / UNBAN — via API
// 
function showBanned(reason) {
    const user = _auth() && _auth().currentUser;
    if (_isAdmin(user)) return;
    const reaEl    = document.getElementById('sysBannedReason');
    const reaWrap  = document.getElementById('sysBannedReasonWrap');
    if (reason) {
        if (reaEl)   reaEl.textContent   = reason;
        if (reaWrap) reaWrap.style.display = 'block';
    }
    document.getElementById('sysBannedOverlay').style.display = 'flex';
    document.querySelectorAll('header, #walletPill, #headerUserChip, #avatarBtn').forEach(el => {
        el.style.pointerEvents = 'none';
    });
}
function hideBanned() {
    document.getElementById('sysBannedOverlay').style.display = 'none';
    document.querySelectorAll('header, #walletPill, #headerUserChip, #avatarBtn').forEach(el => {
        el.style.pointerEvents = '';
    });
}

window.adminBanUser = async function() {
    const statusEl = document.getElementById('adminBanStatus');
    const email  = (document.getElementById('adminBanUid') || {}).value.trim();
    const reason = (document.getElementById('adminBanReason') || {}).value.trim() || 'Terms of Service violation';
    if (!email) { if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = 'Enter an email'; } return; }
    try {
        if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent = 'Banning\u2026'; }
        await adminAPI('POST', 'admin/ban', { email, reason });
        if(statusEl) { statusEl.style.color='#6ee7b7'; statusEl.textContent = 'User banned \u2713'; }
        setTimeout(() => { if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent=''; } }, 3000);
    } catch(e) {
        if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = e.message; }
    }
};

window.adminUnbanUser = async function() {
    const statusEl = document.getElementById('adminBanStatus');
    const email = (document.getElementById('adminBanUid') || {}).value.trim();
    if (!email) { if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = 'Enter an email'; } return; }
    try {
        if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent = 'Unbanning\u2026'; }
        await adminAPI('POST', 'admin/unban', { email });
        if(statusEl) { statusEl.style.color='#6ee7b7'; statusEl.textContent = 'User unbanned \u2713'; }
        setTimeout(() => { if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent=''; } }, 3000);
    } catch(e) {
        if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = e.message; }
    }
};

// 
// GRANT CREDIT
// 
window.adminGrantCredit = async function() {
    const statusEl = document.getElementById('adminGrantStatus');
    const email  = (document.getElementById('adminGrantEmail') || {}).value.trim();
    const amount = parseFloat((document.getElementById('adminGrantAmount') || {}).value || 1);
    if (!email) { if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = 'Enter an email'; } return; }
    if (isNaN(amount) || amount <= 0 || amount > 1) { if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = 'Amount must be $0.01 – $1.00'; } return; }
    try {
        if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent = 'Granting…'; }
        const data = await adminAPI('POST', 'admin/grant-credit', { email, amount });
        if(statusEl) { statusEl.style.color='#6ee7b7'; statusEl.textContent = '$' + amount.toFixed(2) + ' granted (new balance: $' + data.newBalance.toFixed(2) + ')'; }
        setTimeout(() => { if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent=''; } }, 4000);
    } catch(e) {
        if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = e.message; }
    }
};

// 
// APPEALS — loaded via API
// 
window.submitBanAppeal = async function() {
    const btn      = document.getElementById('sysBannedAppealBtn');
    const statusEl = document.getElementById('sysBannedAppealStatus');
    const text     = (document.getElementById('sysBannedAppealText') || {}).value.trim();
    if (!text || text.length < 10) {
        if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent = 'Please write at least a sentence.'; }
        return;
    }
    if(btn) { btn.disabled=true; btn.textContent='Submitting\u2026'; }
    if(statusEl) { statusEl.style.color='#6b6890'; statusEl.textContent=''; }
    try {
        const user = _auth() && _auth().currentUser;
        const fns  = _fns();
        if (!fns || !fns.push) throw new Error('Firebase not ready');
        await fns.push(_ref('/appeals'), {
            uid:     user ? user.uid   : 'unknown',
            email:   user ? user.email : 'unknown',
            message: text,
            ts:      Date.now(),
            status:  'pending'
        });
        if(btn)     { btn.textContent='Appeal Submitted'; btn.style.background='rgba(52,211,153,0.15)'; btn.style.border='1px solid rgba(52,211,153,0.3)'; }
        if(statusEl){ statusEl.style.color='#6ee7b7'; statusEl.textContent='Received \u2014 we\'ll respond within 1\u20133 days.'; }
    } catch(e) {
        if(btn) { btn.disabled=false; btn.textContent='Submit Appeal'; }
        if(statusEl) { statusEl.style.color='#f87171'; statusEl.textContent='Failed to submit. Try again.'; }
    }
};

async function loadAdminAppeals() {
    const listEl  = document.getElementById('adminAppealsList');
    const countEl = document.getElementById('adminAppealCount');
    if (!listEl) return;
    listEl.innerHTML = '<div style="font-size:11px;color:#6b6890;text-align:center;padding:10px 0;">Loading\u2026</div>';
    try {
        const data = await adminAPI('GET', 'admin/appeals');
        const appeals = data.appeals || [];
        if (countEl) countEl.textContent = appeals.length;
        if (!appeals.length) {
            listEl.innerHTML = '<div style="font-size:11px;color:#4a4868;text-align:center;padding:10px 0;">No pending appeals</div>';
            return;
        }
        listEl.innerHTML = appeals.map(a => `
            <div style="background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.07);border-radius:8px;padding:8px 9px;">
                <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px;">
                    <span style="font-size:10px;font-weight:600;color:#ede9ff;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:140px;">${_escHtml(a.email||a.uid||'unknown')}</span>
                    <div style="display:flex;gap:4px;flex-shrink:0;">
                        <button onclick="adminResolveAppeal('${a.key}','approve')" style="font-size:9px;padding:2px 7px;border-radius:5px;background:rgba(52,211,153,0.1);border:1px solid rgba(52,211,153,0.25);color:#6ee7b7;cursor:pointer;font-weight:700;" onmouseover="this.style.background='rgba(52,211,153,0.2)'" onmouseout="this.style.background='rgba(52,211,153,0.1)'">Unban</button>
                        <button onclick="adminResolveAppeal('${a.key}','deny')" style="font-size:9px;padding:2px 7px;border-radius:5px;background:rgba(248,113,113,0.08);border:1px solid rgba(248,113,113,0.2);color:#fca5a5;cursor:pointer;font-weight:700;" onmouseover="this.style.background='rgba(248,113,113,0.18)'" onmouseout="this.style.background='rgba(248,113,113,0.08)'">Deny</button>
                    </div>
                </div>
                <div style="font-size:10px;color:#6b6890;line-height:1.5;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${_escHtml((a.message||'').slice(0,80))}</div>
            </div>
        `).join('');
    } catch(e) {
        listEl.innerHTML = '<div style="font-size:11px;color:#f87171;text-align:center;padding:10px 0;">' + _escHtml(e.message) + '</div>';
    }
}

window.adminResolveAppeal = async function(key, action) {
    try {
        await adminAPI('POST', 'admin/appeals/resolve', { key, action });
        loadAdminAppeals();
    } catch(e) { console.warn('[adminResolveAppeal]', e); }
};

// 
// ADMIN PANEL TOGGLE
// 
window.toggleAdminPanel = function() {
    _panelOpen = !_panelOpen;
    const drawer  = document.getElementById('sysAdminDrawer');
    const chevron = document.getElementById('sysAdminChevron');
    if (drawer)  drawer.style.display  = _panelOpen ? 'block' : 'none';
    if (chevron) chevron.style.transform = _panelOpen ? 'rotate(180deg)' : '';
    if (_panelOpen) loadAdminAppeals();
};

// 
// ADMIN AUTO-PRO + STAT SYNC
// 
function grantAdminPro() {
    const user = _auth() && _auth().currentUser;
    if (!_isAdmin(user)) return;
    if (window._fbUserData) {
        window._fbUserData.plan    = 'Pro';
        window._fbUserData.isAdmin = true;
    }
}

// 
// REALTIME LISTENERS — maintenance + ban status (read-only, rules allow)
// 
function startSysListeners(user) {
    _onVal('/meta/maintenance', function(snap) {
        const data = snap && snap.exists() ? snap.val() : {};
        _maintenanceActive = !!data.active;
        if (_isAdmin(_auth() && _auth().currentUser)) {
            syncMaintenanceUi(data);
            return;
        }
        if (_maintenanceActive) {
            showMaintenance(data.message, data.eta);
        } else {
            hideMaintenance();
        }
    });

    if (user) {
        _onVal('/users/' + user.uid + '/banned', function(snap) {
            const data = snap && snap.exists() ? snap.val() : {};
            if (_isAdmin(user)) return;
            if (data && data.active) {
                _currentUserBanned = true;
                showBanned(data.reason || '');
            } else {
                _currentUserBanned = false;
                hideBanned();
            }
        });
    }
}

// 
// WIRE INTO AUTH STATE
// 
function loadAdminStats() {
    if (!window._adminRevenue) return;
    const d = window._adminRevenue;
    const uEl = document.querySelector('#adminStatUsers div:first-child');
    const lEl = document.querySelector('#adminStatListings div:first-child');
    if (uEl) uEl.textContent = d.userCount   || '—';
    if (lEl) lEl.textContent = d.listingCount || '—';
}

async function onAuthReady(user) {
    // Load admin email from Firebase before any _isAdmin() check
    await _loadAdminEmail();
    if (_isAdmin(user)) {
        document.getElementById('sysAdminPanel').style.display = 'block';
        const closeBtn = document.getElementById('sysMaintenanceCloseBtn');
        if (closeBtn) closeBtn.style.display = 'inline-flex';
        grantAdminPro();
        setTimeout(loadAdminStats, 2000);
    } else {
        document.getElementById('sysAdminPanel').style.display = 'none';
    }
    startSysListeners(user);
}

function _escHtml(s) {
    return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

let _authWaitMs = 0;
function waitForAuth() {
    const auth = _auth();
    if (auth && auth.onAuthStateChanged) {
        auth.onAuthStateChanged(function(user) {
            onAuthReady(user || null);
        });
        startSysListeners(null);
    } else if (_authWaitMs < 8000) {
        _authWaitMs += 120;
        setTimeout(waitForAuth, 120);
    }
}
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', waitForAuth);
} else {
    waitForAuth();
}

})();




        
